def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        complexity_factor = 1.0
        if ratio < 0.15:
            for a in range(1, 15):
                base = np.sin(ratio * a * np.pi) + 1.5
                modifier = np.log1p(a ** 2) * (a % 4 + 1)
                score += base * modifier
                if a % 5 == 0:
                    score *= 0.92
            if (capacity * item) % 7 == 0:
                score *= 0.85
            if score > 30:
                score /= 3.5
            complexity_factor = np.sqrt(capacity) / (1 + ratio * 10)
        elif 0.15 <= ratio < 0.4:
            prod = 1.0
            for n in range(1, int(capacity) + 1):
                term = (ratio + n / (n + 2)) ** 1.7
                if term > 1e4:
                    term = np.cbrt(term)
                prod *= term
                if prod > 1e7:
                    prod = np.log1p(prod)
                    break
            score += np.cbrt(prod) + (capacity % 10)
            if (int(capacity) % 4 == 0) and ((int(item * 10)) % 6 == 0):
                score += 7.5
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 8):
                fraction = ((ratio * x**3) % 1)
                weight = (x ** 2) * np.log1p(x)
                extra_sum += fraction * weight
            score += extra_sum / 7
            complexity_factor = np.log1p(score + 1)
        elif 0.4 <= ratio <= 0.7:
            for m in range(1, 10):
                term = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += term
            diff = capacity - item
            if diff < 5:
                score += 15 + diff * 0.7
            else:
                score -= diff * 1.1
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 9 == 0:
                score *= 1.25
            if score > 25:
                score /= 4
            complexity_factor = np.power(diff + 1, 0.8)
        elif 0.7 < ratio <= 1.1:
            penalty_base = 0.0
            for p in range(1, 14):
                power_term = ((ratio - 0.7) ** p) * (p ** 1.8)
                if power_term > 70:
                    power_term = np.sqrt(power_term)
                penalty_base += power_term
                if penalty_base > 80:
                    penalty_base = np.log1p(penalty_base ** 1.2)
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 8 == 0) and (int(item * 7) % 12 == 0):
                score -= 9
            if score < 0:
                score = abs(score) * 1.6 + 6
            if score > 150:
                score = 150
            complexity_factor = np.log1p(score + 2)
        elif 1.1 < ratio <= 1.8:
            penalty_ext = 0.0
            diff = ratio - 1.1
            for q in range(1, 16):
                term = ((diff) ** q) * (q ** 3.2) / (q + 2)
                if term > 5000:
                    term = np.cbrt(term) * 2
                penalty_ext += term
            score = penalty_ext * 22
            if capacity < item * 1.5:
                score += 25
            if (int(capacity * 2) % 6 == 0) and (int(item * 10) % 5 == 0):
                score -= 12
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6 + 7
            if score > 1800:
                score = 1800
            complexity_factor = np.sqrt(score + 10)
        else:
            super_penalty = 0.0
            diff = ratio - 1.8
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 20000:
                    term = np.cbrt(term) * 5
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 17) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 15
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 8
            if score > 2500:
                score = 2500
            complexity_factor = (np.log1p(score) + 5) / 2
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            complexity_factor /= 2
        elif capacity < 10:
            score *= 2.8
            complexity_factor *= 1.5
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score * complexity_factor
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        high_count = np.sum(finite_priorities > q3)
        median_val = q2
        fill_value = np.max(finite_priorities) * (10 + high_count) - median_val * 0.8
    priorities[np.isinf(priorities)] = fill_value
    median_finite = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_finite
    return priorities
